1	//! Debug library — Rust port of `ldblib.c`.
2	//!
3	//! Provides the `debug` Lua standard library module. Exposes debug
4	//! introspection APIs: stack inspection (`getinfo`, `getlocal`), upvalue
5	//! access (`getupvalue`, `setupvalue`, `upvaluejoin`), hook management
6	//! (`sethook`, `gethook`), metatable overrides (`getmetatable`,
7	//! `setmetatable`), userdata values (`getuservalue`, `setuservalue`),
8	//! and utility functions (`traceback`, `debug`, `setcstacklimit`).
9	//!
10	//! C source: `reference/lua-5.4.7/src/ldblib.c` (484 lines, 20 functions)
11	
12	use std::io::{self, BufRead, Write};
13	
14	use lua_types::{GcRef, LuaError, LuaString, LuaType, LuaValue, LuaStatus};
15	use crate::state_stub::{LuaState, LuaStateStubExt as _, lua_CFunction, upvalue_index, CompareOp, LuaDebug as DebugInfo};
16	
17	// ── Constants ──────────────────────────────────────────────────────────────
18	
19	/// Registry key for the hook table that maps threads to their hook functions.
20	///
21	/// C: `static const char *const HOOKKEY = "_HOOKKEY";`
22	const HOOKKEY: &[u8] = b"_HOOKKEY";
23	
24	/// Hook event names indexed by the raw event code stored in [`DebugInfo::event`].
25	/// Order must match the `LUA_HOOK*` constants: Call=0, Return=1, Line=2, Count=3, TailCall=4.
26	///
27	/// C: `static const char *const hooknames[] = {"call","return","line","count","tail call"};`
28	const HOOKNAMES: &[&[u8]; 5] = &[b"call", b"return", b"line", b"count", b"tail call"];
29	
30	/// Bitmask constants for hook event selection.
31	/// C: `LUA_MASKCALL`, `LUA_MASKRET`, `LUA_MASKLINE`, `LUA_MASKCOUNT`
32	const MASK_CALL: u32 = 1 << 0;
33	const MASK_RET: u32 = 1 << 1;
34	const MASK_LINE: u32 = 1 << 2;
35	const MASK_COUNT: u32 = 1 << 3;
36	
37	// ── Local type aliases ─────────────────────────────────────────────────────
38	
39	/// Entry-point signature for a Lua stdlib function in Rust.
40	pub(crate) type LibFn = fn(&mut LuaState) -> Result<usize, LuaError>;
41	
42	/// A Rust hook callback registered with the Lua VM's hook mechanism.
43	///
44	/// C: `lua_Hook` = `void (*)(lua_State *, lua_Debug *)`
45	pub(crate) type HookFn = fn(&mut LuaState, &mut DebugInfo) -> Result<(), LuaError>;
46	
47	/// Opaque identity handle for an upvalue.
48	///
49	/// C: `void *` returned by `lua_upvalueid`. Lua uses pointer equality to
50	/// check whether two upvalues share the same storage cell.
51	///
52	/// TODO(port): In C this is a raw pointer into the upvalue's storage cell.
53	/// Safe Rust cannot expose a raw pointer outside `lua-gc`. A stable u64 ID
54	/// or a GcRef-based comparison should be designed in Phase D. Using `usize`
55	/// (pointer-sized) as a placeholder so the call sites compile.
56	type UpvalId = usize;
57	
58	// ── Internal helpers ───────────────────────────────────────────────────────
59	
60	/// Ensure the cross-thread target has room for `n` more stack slots.
61	///
62	/// When the target is the current thread this is a no-op because the current
63	/// thread's stack is managed by the caller. When it is another thread we
64	/// must verify its stack, but that requires a simultaneous `&mut LuaState`
65	/// for both threads.
66	///
67	/// C: `static void checkstack(lua_State *L, lua_State *L1, int n)`
68	fn check_cross_thread_stack(
69	    state: &mut LuaState,
70	    target_is_self: bool,
71	    n: i32,
72	) -> Result<(), LuaError> {
73	    // C: if (l_unlikely(L != L1 && !lua_checkstack(L1, n)))
74	    //        luaL_error(L, "stack overflow");
75	    if !target_is_self {
76	        // TODO(port): checking a different thread's stack requires simultaneous
77	        // `&mut LuaState` for both threads, which is not expressible in safe Rust
78	        // without interior mutability. Conservatively checks the current state only.
79	        state.ensure_stack(n, "stack overflow")?;
80	    }
81	    Ok(())
82	}
83	
84	/// Inspect argument 1: if it is a thread value, return `(1, Some(thread_ref))`;
85	/// otherwise return `(0, None)` meaning "operate on the current state".
86	///
87	/// C: `static lua_State *getthread(lua_State *L, int *arg)`
88	fn getthread(state: &mut LuaState) -> (i32, Option<GcRef<lua_types::value::LuaThread>>) {
89	    // C: if (lua_isthread(L, 1)) { *arg = 1; return lua_tothread(L, 1); }
90	    if state.type_at(1) == LuaType::Thread {
91	        let thread = state.to_thread_at(1);
92	        return (1, thread);
93	    }
94	    // C: *arg = 0; return L;
95	    (0, None)
96	}
97	
98	/// Push byte string `v` (or Nil when `v` is `None`) and store it under key
99	/// `k` in the table that sits at stack position -2.
100	///
101	/// C: `static void settabss(lua_State *L, const char *k, const char *v)`
102	/// PORT NOTE: The C version passes NULL to signal "no value" (lua_pushstring
103	/// with NULL pushes nil). Rust uses Option<&[u8]> for the same semantics.
104	fn settabss(state: &mut LuaState, k: &[u8], v: Option<&[u8]>) -> Result<(), LuaError> {
105	    // C: lua_pushstring(L, v);  /* NULL -> nil */
106	    match v {
107	        Some(s) => {
108	            let ls = state.intern_str(s)?;
109	            state.push(LuaValue::Str(ls));
110	        }
111	        None => { state.push(LuaValue::Nil); }
112	    }
113	    // C: lua_setfield(L, -2, k);
114	    state.set_field(-2, k)
115	}
116	
117	/// Push integer `v` and store it under key `k` in the table at -2.
118	///
119	/// C: `static void settabsi(lua_State *L, const char *k, int v)`
120	fn settabsi(state: &mut LuaState, k: &[u8], v: i32) -> Result<(), LuaError> {
121	    // C: lua_pushinteger(L, v); lua_setfield(L, -2, k);
122	    state.push(LuaValue::Int(v as i64));
123	    state.set_field(-2, k)
124	}
125	
126	/// Push boolean `v` and store it under key `k` in the table at -2.
127	///
128	/// C: `static void settabsb(lua_State *L, const char *k, int v)`
129	fn settabsb(state: &mut LuaState, k: &[u8], v: bool) -> Result<(), LuaError> {
130	    // C: lua_pushboolean(L, v); lua_setfield(L, -2, k);
131	    state.push(LuaValue::Bool(v));
132	    state.set_field(-2, k)
133	}
134	
135	/// After `lua_getinfo` has pushed a result ('f' function or 'L' line table)
136	/// onto L1's stack, move it into the result table on L as field `fname`.
137	///
138	/// When target is self, the value is already on our stack; rotate to bring
139	/// it above the result table. When target is a different thread, use xmove.
140	///
141	/// C: `static void treatstackoption(lua_State *L, lua_State *L1, const char *fname)`
142	fn treat_stack_option(
143	    state: &mut LuaState,
144	    target_is_self: bool,
145	    fname: &[u8],
146	) -> Result<(), LuaError> {
147	    if target_is_self {
148	        // C: lua_rotate(L, -2, 1);  /* exchange object and table */
149	        state.rotate(-2, 1);
150	    } else {
151	        // C: lua_xmove(L1, L, 1);  /* move object to the "main" stack */
152	        // TODO(port): moving a value from another thread's stack (lua_xmove)
153	        // requires simultaneous `&mut LuaState` for both threads. Not expressible
154	        // in safe Rust without interior mutability. Pushes Nil as placeholder.
155	        state.push(LuaValue::Nil);
156	    }
157	    // C: lua_setfield(L, -2, fname);
158	    state.set_field(-2, fname)
159	}
