161	// ── Library functions ──────────────────────────────────────────────────────
162	
163	/// `debug.getregistry()` — return the Lua registry table.
164	///
165	/// C: `static int db_getregistry(lua_State *L)`
166	pub(crate) fn get_registry(state: &mut LuaState) -> Result<usize, LuaError> {
167	    // C: lua_pushvalue(L, LUA_REGISTRYINDEX); return 1;
168	    state.push_registry();
169	    Ok(1)
170	}
