172	/// `debug.getmetatable(obj)` — return the metatable of `obj`, or nil if none.
173	///
174	/// C: `static int db_getmetatable(lua_State *L)`
175	pub(crate) fn get_metatable(state: &mut LuaState) -> Result<usize, LuaError> {
176	    // C: luaL_checkany(L, 1);
177	    state.check_arg_any(1)?;
178	    // C: if (!lua_getmetatable(L, 1)) lua_pushnil(L);
179	    if !state.get_metatable(1)? {
180	        state.push(LuaValue::Nil);
181	    }
182	    Ok(1)
183	}
184	
185	/// `debug.setmetatable(obj, table)` — set `table` (or nil) as `obj`'s metatable.
186	/// Returns the first argument `obj`.
187	///
188	/// C: `static int db_setmetatable(lua_State *L)`
189	pub(crate) fn set_metatable(state: &mut LuaState) -> Result<usize, LuaError> {
190	    // C: int t = lua_type(L, 2);
191	    let t = state.type_at(2);
192	    // C: luaL_argexpected(L, t == LUA_TNIL || t == LUA_TTABLE, 2, "nil or table");
193	    if !(t == LuaType::Nil || t == LuaType::Table) {
194	        let got = state.arg(2);
195	        return Err(LuaError::type_arg_error(2, "nil or table", &got));
196	    }
197	    // C: lua_settop(L, 2); lua_setmetatable(L, 1); return 1;
198	    lua_vm::api::set_top(state, 2)?;
199	    state.set_metatable(1)?;
200	    Ok(1)
201	}
