203	/// `debug.getuservalue(obj [, n])` — return the n-th user value of userdata
204	/// `obj` plus `true`, or the fail value if `obj` is not userdata or `n` is out
205	/// of range.
206	///
207	/// C: `static int db_getuservalue(lua_State *L)`
208	pub(crate) fn get_uservalue(state: &mut LuaState) -> Result<usize, LuaError> {
209	    // C: int n = (int)luaL_optinteger(L, 2, 1);
210	    let n = state.opt_arg_integer(2, 1)? as i32;
211	    // C: if (lua_type(L, 1) != LUA_TUSERDATA) luaL_pushfail(L);
212	    if state.type_at(1) != LuaType::UserData {
213	        state.push_fail();
214	        return Ok(1);
215	    }
216	    // C: else if (lua_getiuservalue(L, 1, n) != LUA_TNONE) { lua_pushboolean(L, 1); return 2; }
217	    let ty = state.get_iuservalue(1, n)?;
218	    if ty != LuaType::None {
219	        state.push(LuaValue::Bool(true));
220	        return Ok(2);
221	    }
222	    Ok(1)
223	}
224	
225	/// `debug.setuservalue(obj, value [, n])` — set the n-th user value of userdata
226	/// `obj` to `value`. Returns `obj`, or the fail value on failure.
227	///
228	/// C: `static int db_setuservalue(lua_State *L)`
229	pub(crate) fn set_uservalue(state: &mut LuaState) -> Result<usize, LuaError> {
230	    // C: int n = (int)luaL_optinteger(L, 3, 1);
231	    let n = state.opt_arg_integer(3, 1)? as i32;
232	    // C: luaL_checktype(L, 1, LUA_TUSERDATA);
233	    state.check_arg_type(1, LuaType::UserData)?;
234	    // C: luaL_checkany(L, 2);
235	    state.check_arg_any(2)?;
236	    // C: lua_settop(L, 2);
237	    lua_vm::api::set_top(state, 2)?;
238	    // C: if (!lua_setiuservalue(L, 1, n)) luaL_pushfail(L);
239	    if !state.set_iuservalue(1, n)? {
240	        state.push_fail();
241	    }
242	    Ok(1)
243	}
