245	/// `debug.getinfo([thread,] f|level [, what])` — collect debug information
246	/// about function `f` or stack level `level` into a new table. The `what`
247	/// string selects which fields to populate (default `"flnSrtu"`).
248	///
249	/// C: `static int db_getinfo(lua_State *L)`
250	pub(crate) fn get_info(state: &mut LuaState) -> Result<usize, LuaError> {
251	    let mut ar = DebugInfo::default();
252	
253	    // C: int arg; lua_State *L1 = getthread(L, &arg);
254	    let (arg, other_thread) = getthread(state);
255	    let target_is_self = other_thread.is_none();
256	
257	    // C: const char *options = luaL_optstring(L, arg+2, "flnSrtu");
258	    // to_vec() immediately to avoid borrow-checker conflict with subsequent &mut state ops.
259	    let raw_opts: Vec<u8> = state.opt_arg_string(arg + 2, b"flnSrtu")?.to_vec();
260	
261	    // C: checkstack(L, L1, 3);
262	    check_cross_thread_stack(state, target_is_self, 3)?;
263	
264	    // C: luaL_argcheck(L, options[0] != '>', arg + 2, "invalid option '>'");
265	    if raw_opts.first() == Some(&b'>') {
266	        return Err(LuaError::arg_error(arg + 2, "invalid option '>'"));
267	    }
268	
269	    // Build the effective options string, prepending '>' when the subject is a function.
270	    let options: Vec<u8>;
271	
272	    if state.type_at(arg + 1) == LuaType::Function {
273	        // C: options = lua_pushfstring(L, ">%s", options);  /* add '>' to options */
274	        // In C this also pushes the string onto the stack; in Rust we just build a Vec.
275	        let mut prefixed = Vec::with_capacity(raw_opts.len() + 1);
276	        prefixed.push(b'>');
277	        prefixed.extend_from_slice(&raw_opts);
278	        options = prefixed;
279	
280	        // C: lua_pushvalue(L, arg + 1);  /* move function to L1 stack */
281	        // C: lua_xmove(L, L1, 1);
282	        if target_is_self {
283	            state.push_value_at(arg + 1)?;
284	        } else {
285	            // TODO(port): lua_xmove to another thread's stack requires simultaneous
286	            // `&mut LuaState` for both threads. Cross-thread getinfo with a function
287	            // argument is left incomplete for Phase A.
288	        }
289	
290	        // C: if (!lua_getinfo(L1, options, &ar)) return luaL_argerror(...);
291	        // With '>' prefix, get_debug_info consumes the function from the top of stack.
292	        if state.get_debug_info(&options, &mut ar).is_err() {
293	            return Err(LuaError::arg_error(arg + 2, "invalid option"));
294	        }
295	    } else {
296	        options = raw_opts;
297	
298	        // C: if (!lua_getstack(L1, (int)luaL_checkinteger(L, arg+1), &ar)) { fail }
299	        let level = state.check_arg_integer(arg + 1)? as i32;
300	        if !state.get_stack_level(level, &mut ar) {
301	            // C: luaL_pushfail(L); return 1;
302	            state.push_fail()?;
303	            return Ok(1);
304	        }
305	
306	        // C: if (!lua_getinfo(L1, options, &ar)) return luaL_argerror(...);
307	        if state.get_debug_info(&options, &mut ar).is_err() {
308	            return Err(LuaError::arg_error(arg + 2, "invalid option"));
309	        }
310	    }
311	
312	    // C: lua_newtable(L);  /* table to collect results */
313	    let result_tbl = state.new_table();
314	    state.push(LuaValue::Table(result_tbl));
315	
316	    // C: if (strchr(options, 'S')) { ... }
317	    if options.contains(&b'S') {
318	        // C: lua_pushlstring(L, ar.source, ar.srclen); lua_setfield(L, -2, "source");
319	        let src = state.intern_str(ar.source_bytes())?;
320	        state.push(LuaValue::Str(src));
321	        state.set_field(-2, b"source")?;
322	
323	        settabss(state, b"short_src", Some(ar.short_src_bytes()))?;
324	        settabsi(state, b"linedefined", ar.linedefined)?;
325	        settabsi(state, b"lastlinedefined", ar.lastlinedefined)?;
326	        settabss(state, b"what", Some(ar.what_bytes()))?;
327	    }
328	    if options.contains(&b'l') {
329	        settabsi(state, b"currentline", ar.currentline)?;
330	    }
331	    if options.contains(&b'u') {
332	        settabsi(state, b"nups", ar.nups as i32)?;
333	        settabsi(state, b"nparams", ar.nparams as i32)?;
334	        settabsb(state, b"isvararg", ar.isvararg)?;
335	    }
336	    if options.contains(&b'n') {
337	        // ar.name may be NULL in C → None in Rust.
338	        settabss(state, b"name", Some(ar.name_bytes()))?;
339	        // ar.namewhat is always non-NULL in C (may be empty string).
340	        settabss(state, b"namewhat", Some(ar.namewhat_bytes()))?;
341	    }
342	    if options.contains(&b'r') {
343	        settabsi(state, b"ftransfer", ar.ftransfer as i32)?;
344	        settabsi(state, b"ntransfer", ar.ntransfer as i32)?;
345	    }
346	    if options.contains(&b't') {
347	        settabsb(state, b"istailcall", ar.istailcall)?;
348	    }
349	    // 'L' and 'f' options: lua_getinfo pushed line-table then function onto L1's stack.
350	    // treat_stack_option moves each into the result table.
351	    // PORT NOTE: C's lua_getinfo always pushes 'f' result before 'L' result (regardless
352	    // of option-string order), so the treatstackoption calls below are intentionally
353	    // ordered 'L' first then 'f' — matching the C db_getinfo exactly.
354	    if options.contains(&b'L') {
355	        treat_stack_option(state, target_is_self, b"activelines")?;
356	    }
357	    if options.contains(&b'f') {
358	        treat_stack_option(state, target_is_self, b"func")?;
359	    }
360	
361	    Ok(1)
362	}
