364	/// `debug.getlocal([thread,] level, local)` — return the name and value of
365	/// local variable `local` at stack level `level`.
366	///
367	/// When the first argument is a function, returns only the parameter name at
368	/// position `local` (no value).
369	///
370	/// C: `static int db_getlocal(lua_State *L)`
371	pub(crate) fn get_local(state: &mut LuaState) -> Result<usize, LuaError> {
372	    // C: int arg; lua_State *L1 = getthread(L, &arg);
373	    let (arg, other_thread) = getthread(state);
374	    let target_is_self = other_thread.is_none();
375	
376	    // C: int nvar = (int)luaL_checkinteger(L, arg + 2);
377	    let nvar = state.check_arg_integer(arg + 2)? as i32;
378	
379	    // C: if (lua_isfunction(L, arg + 1)) { ... }
380	    if state.type_at(arg + 1) == LuaType::Function {
381	        // C: lua_pushvalue(L, arg + 1);  /* push function */
382	        state.push_value_at(arg + 1)?;
383	        // C: lua_pushstring(L, lua_getlocal(L, NULL, nvar));
384	        // lua_getlocal with NULL ar reads parameter names from the function at the
385	        // top of the stack; it does NOT push a value.
386	        let name = state.get_param_name(0, nvar)?;
387	        match name {
388	            Some(n) => {
389	                let ls = state.intern_str(&n)?;
390	                state.push(LuaValue::Str(ls));
391	            }
392	            None => { state.push(LuaValue::Nil); }
393	        }
394	        // C: return 1;  /* return only name (there is no value) */
395	        // The pushed function below name is discarded by the VM when it collects
396	        // exactly 1 return value from the top of the stack.
397	        return Ok(1);
398	    }
399	
400	    // Stack-level path.
401	    // C: int level = (int)luaL_checkinteger(L, arg + 1);
402	    let level = state.check_arg_integer(arg + 1)? as i32;
403	    let mut ar = DebugInfo::default();
404	
405	    // C: if (l_unlikely(!lua_getstack(L1, level, &ar))) return luaL_argerror(...);
406	    if !state.get_stack_level(level, &mut ar) {
407	        return Err(LuaError::arg_error(arg + 1, "level out of range"));
408	    }
409	    check_cross_thread_stack(state, target_is_self, 1)?;
410	
411	    // C: name = lua_getlocal(L1, &ar, nvar);
412	    // Pushes the local's value onto L1's stack and returns its name.
413	    let name = state.get_local_at(&ar, nvar)?;
414	
415	    if let Some(n) = name {
416	        if !target_is_self {
417	            // C: lua_xmove(L1, L, 1);  /* move local value */
418	            // TODO(port): cross-thread local value move (lua_xmove). The value was
419	            // pushed onto the other thread's stack; moving it to the current stack
420	            // requires simultaneous mutable access to two LuaState instances.
421	        }
422	        // C: lua_pushstring(L, name); lua_rotate(L, -2, 1); return 2;
423	        let ls = state.intern_str(&n)?;
424	        state.push(LuaValue::Str(ls));
425	        state.rotate(-2, 1)?;
426	        Ok(2)
427	    } else {
428	        // C: luaL_pushfail(L); return 1;
429	        state.push_fail()?;
430	        Ok(1)
431	    }
432	}
