434	/// `debug.setlocal([thread,] level, local, value)` — set local variable
435	/// `local` at stack level `level` to `value`. Returns the variable name, or
436	/// nil on failure.
437	///
438	/// C: `static int db_setlocal(lua_State *L)`
439	pub(crate) fn set_local(state: &mut LuaState) -> Result<usize, LuaError> {
440	    // C: int arg; lua_State *L1 = getthread(L, &arg);
441	    let (arg, other_thread) = getthread(state);
442	    let target_is_self = other_thread.is_none();
443	
444	    // C: int level = (int)luaL_checkinteger(L, arg + 1);
445	    let level = state.check_arg_integer(arg + 1)? as i32;
446	    // C: int nvar = (int)luaL_checkinteger(L, arg + 2);
447	    let nvar = state.check_arg_integer(arg + 2)? as i32;
448	
449	    let mut ar = DebugInfo::default();
450	    // C: if (l_unlikely(!lua_getstack(L1, level, &ar))) return luaL_argerror(...);
451	    if !state.get_stack_level(level, &mut ar) {
452	        return Err(LuaError::arg_error(arg + 1, "level out of range"));
453	    }
454	
455	    // C: luaL_checkany(L, arg+3);
456	    state.check_arg_any(arg + 3)?;
457	    // C: lua_settop(L, arg+3);
458	    lua_vm::api::set_top(state, arg + 3)?;
459	
460	    check_cross_thread_stack(state, target_is_self, 1)?;
461	
462	    // C: lua_xmove(L, L1, 1);  /* move value to L1 */
463	    if !target_is_self {
464	        // TODO(port): cross-thread value transfer (lua_xmove) before setlocal.
465	        // The new value must be on L1's stack for lua_setlocal to consume it.
466	    }
467	
468	    // C: name = lua_setlocal(L1, &ar, nvar);  /* pops value from L1 */
469	    let name = state.set_local_at(&ar, nvar)?;
470	
471	    // C: if (name == NULL) lua_pop(L1, 1);  /* pop value if not consumed */
472	    if name.is_none() {
473	        state.pop_n(1);
474	    }
475	
476	    // C: lua_pushstring(L, name);
477	    match name {
478	        Some(n) => {
479	            let ls = state.intern_str(&n)?;
480	            state.push(LuaValue::Str(ls));
481	        }
482	        None => { state.push(LuaValue::Nil); }
483	    }
484	    Ok(1)
485	}
