487	/// Shared implementation for `get_upvalue` and `set_upvalue`.
488	///
489	/// When `get` is `true`, retrieves upvalue `n` of the function at stack index 1,
490	/// pushes its value, and returns `(name, value)` — 2 results.
491	///
492	/// When `get` is `false`, pops the top stack value and installs it as upvalue
493	/// `n`, returning `(name,)` — 1 result.
494	///
495	/// Returns 0 results when the upvalue index is out of range.
496	///
497	/// C: `static int auxupvalue(lua_State *L, int get)`
498	fn aux_upvalue(state: &mut LuaState, get: bool) -> Result<usize, LuaError> {
499	    // C: int n = (int)luaL_checkinteger(L, 2);
500	    let n = state.check_arg_integer(2)? as i32;
501	    // C: luaL_checktype(L, 1, LUA_TFUNCTION);
502	    state.check_arg_type(1, LuaType::Function)?;
503	
504	    // C: name = get ? lua_getupvalue(L, 1, n) : lua_setupvalue(L, 1, n);
505	    let name: Option<Vec<u8>> = if get {
506	        // lua_getupvalue pushes the upvalue value and returns the name.
507	        state.get_upvalue(1, n)?
508	    } else {
509	        // lua_setupvalue pops the top-of-stack value, sets upvalue n, returns name.
510	        state.set_upvalue(1, n)?
511	    };
512	
513	    // C: if (name == NULL) return 0;
514	    let name_ref = match name {
515	        Some(n) => n,
516	        None => return Ok(0),
517	    };
518	
519	    // C: lua_pushstring(L, name);
520	    let ls = state.intern_str(&name_ref)?;
521	    state.push(LuaValue::Str(ls));
522	
523	    // C: lua_insert(L, -(get+1));  /* no-op if get is false */
524	    // When get=true: stack is [..., value, name]; insert at -2 → [..., name, value].
525	    // When get=false: insert at -1 is a no-op; stack is [..., name].
526	    if get {
527	        state.insert(-2)?;
528	    }
529	
530	    // C: return get + 1;
531	    Ok(if get { 2 } else { 1 })
532	}
