553	/// Verify that upvalue `argnup` of function at stack index `argf` exists.
554	/// Returns the opaque identity handle and the upvalue index.
555	/// If `require_valid` is true, raises an arg error when the upvalue is absent.
556	///
557	/// C: `static void *checkupval(lua_State *L, int argf, int argnup, int *pnup)`
558	fn check_upval(
559	    state: &mut LuaState,
560	    argf: i32,
561	    argnup: i32,
562	    require_valid: bool,
563	) -> Result<(Option<UpvalId>, i32), LuaError> {
564	    // C: int nup = (int)luaL_checkinteger(L, argnup);
565	    let nup = state.check_arg_integer(argnup)? as i32;
566	    // C: luaL_checktype(L, argf, LUA_TFUNCTION);
567	    state.check_arg_type(argf, LuaType::Function)?;
568	    // C: id = lua_upvalueid(L, argf, nup);
569	    // TODO(port): lua_upvalueid returns a raw void* that uniquely identifies
570	    // an upvalue's storage cell. A safe equivalent (e.g., GcRef<UpVal> pointer
571	    // comparison, or a stable u64 ID from the GC layer) must be defined in
572	    // Phase D. Using Option<usize> as placeholder.
573	    let id: Option<UpvalId> = match state.upvalue_id(argf, nup) {
574	        Ok(p) if p.is_null() => None,
575	        Ok(p) => Some(p as usize),
576	        Err(_) => None,
577	    };
578	    // C: if (pnup) { luaL_argcheck(L, id != NULL, argnup, "invalid upvalue index"); *pnup = nup; }
579	    if require_valid && id.is_none() {
580	        return Err(LuaError::arg_error(argnup, "invalid upvalue index"));
581	    }
582	    Ok((id, nup))
583	}
