585	/// `debug.upvalueid(f, n)` — return a unique identifier for upvalue `n` of
586	/// function `f` as a light userdata. Returns fail on out-of-range index.
587	///
588	/// C: `static int db_upvalueid(lua_State *L)`
589	pub(crate) fn upvalue_id(state: &mut LuaState) -> Result<usize, LuaError> {
590	    // C: void *id = checkupval(L, 1, 2, NULL);
591	    let (id, _nup) = check_upval(state, 1, 2, false)?;
592	    match id {
593	        Some(uid) => {
594	            // C: lua_pushlightuserdata(L, id);
595	            lua_vm::api::push_light_userdata(state, uid as *mut core::ffi::c_void);
596	        }
597	        None => {
598	            // C: luaL_pushfail(L);
599	            state.push_fail()?;
600	        }
601	    }
602	    Ok(1)
603	}
