605	/// `debug.upvaluejoin(f1, n1, f2, n2)` — make upvalue `n1` of function `f1`
606	/// refer to the same storage as upvalue `n2` of function `f2`.
607	///
608	/// C: `static int db_upvaluejoin(lua_State *L)`
609	pub(crate) fn upvalue_join(state: &mut LuaState) -> Result<usize, LuaError> {
610	    // C: int n1, n2;
611	    // C: checkupval(L, 1, 2, &n1);
612	    let (_id1, n1) = check_upval(state, 1, 2, true)?;
613	    // C: checkupval(L, 3, 4, &n2);
614	    let (_id2, n2) = check_upval(state, 3, 4, true)?;
615	    // C: luaL_argcheck(L, !lua_iscfunction(L, 1), 1, "Lua function expected");
616	    if state.is_c_function_at(1) {
617	        return Err(LuaError::arg_error(1, "Lua function expected"));
618	    }
619	    // C: luaL_argcheck(L, !lua_iscfunction(L, 3), 3, "Lua function expected");
620	    if state.is_c_function_at(3) {
621	        return Err(LuaError::arg_error(3, "Lua function expected"));
622	    }
623	    // C: lua_upvaluejoin(L, 1, n1, 3, n2);
624	    state.join_upvalues(1, n1, 3, n2)?;
625	    Ok(0)
626	}
