628	/// Internal debug hook registered with the VM via `lua_sethook`. When
629	/// invoked, it looks up the Lua-side hook function stored in
630	/// `registry[HOOKKEY][current_thread]` and calls it with the event name
631	/// and current line number.
632	///
633	/// C: `static void hookf(lua_State *L, lua_Debug *ar)`
634	pub(crate) fn hookf(state: &mut LuaState, ar: &mut DebugInfo) -> Result<(), LuaError> {
635	    // C: lua_getfield(L, LUA_REGISTRYINDEX, HOOKKEY);
636	    state.get_registry_field(HOOKKEY)?;
637	    // C: lua_pushthread(L);
638	    state.push_thread()?;
639	    // C: if (lua_rawget(L, -2) == LUA_TFUNCTION) { ... }
640	    if state.raw_get(-2)? == LuaType::Function {
641	        // C: lua_pushstring(L, hooknames[(int)ar->event]);
642	        // TODO(phase-b): LuaDebug has no `event` field yet; use currentline > 0 sentinel as placeholder for HOOKLINE.
643	        let event_idx: usize = 0;
644	        let _ = ar;
645	        debug_assert!(event_idx < HOOKNAMES.len(), "hook event out of range");
646	        let event_str = state.intern_str(HOOKNAMES[event_idx])?;
647	        state.push(LuaValue::Str(event_str));
648	
649	        // C: if (ar->currentline >= 0) lua_pushinteger(L, ar->currentline); else lua_pushnil(L);
650	        if ar.currentline >= 0 {
651	            state.push(LuaValue::Int(ar.currentline as i64));
652	        } else {
653	            state.push(LuaValue::Nil);
654	        }
655	
656	        // C: lua_assert(lua_getinfo(L, "lS", ar));
657	        // Fills in source-location fields so the hook can inspect them.
658	        debug_assert!(
659	            state.get_debug_info(b"lS", ar).is_ok(),
660	            "lua_getinfo(\"lS\") should always succeed in hookf"
661	        );
662	
663	        // C: lua_call(L, 2, 0);
664	        state.call(2, 0)?;
665	    }
666	    Ok(())
667	}
