669	/// Convert the string hook-mask (`'c'`/`'r'`/`'l'` characters) and a count
670	/// to the integer bitmask used by the VM's `sethook` API.
671	///
672	/// C: `static int makemask(const char *smask, int count)`
673	fn make_mask(smask: &[u8], count: i32) -> u32 {
674	    let mut mask: u32 = 0;
675	    // C: if (strchr(smask, 'c')) mask |= LUA_MASKCALL;
676	    if smask.contains(&b'c') {
677	        mask |= MASK_CALL;
678	    }
679	    // C: if (strchr(smask, 'r')) mask |= LUA_MASKRET;
680	    if smask.contains(&b'r') {
681	        mask |= MASK_RET;
682	    }
683	    // C: if (strchr(smask, 'l')) mask |= LUA_MASKLINE;
684	    if smask.contains(&b'l') {
685	        mask |= MASK_LINE;
686	    }
687	    // C: if (count > 0) mask |= LUA_MASKCOUNT;
688	    if count > 0 {
689	        mask |= MASK_COUNT;
690	    }
691	    mask
692	}
693	
694	/// Convert the integer hook bitmask back to the string representation used in
695	/// Lua (`'c'`/`'r'`/`'l'` characters).
696	///
697	/// C: `static char *unmakemask(int mask, char *smask)`
698	fn unmake_mask(mask: u32) -> Vec<u8> {
699	    let mut smask = Vec::with_capacity(3);
700	    // C: if (mask & LUA_MASKCALL) smask[i++] = 'c'; ...
701	    if mask & MASK_CALL != 0 {
702	        smask.push(b'c');
703	    }
704	    if mask & MASK_RET != 0 {
705	        smask.push(b'r');
706	    }
707	    if mask & MASK_LINE != 0 {
708	        smask.push(b'l');
709	    }
710	    smask
711	}
