713	/// `debug.sethook([thread,] hook, mask [, count])` — install a debug hook.
714	/// Passing nil as `hook` removes the current hook.
715	///
716	/// C: `static int db_sethook(lua_State *L)`
717	pub(crate) fn set_hook(state: &mut LuaState) -> Result<usize, LuaError> {
718	    // C: int arg, mask, count; lua_Hook func;
719	    // C: lua_State *L1 = getthread(L, &arg);
720	    let (arg, other_thread) = getthread(state);
721	    let target_is_self = other_thread.is_none();
722	
723	    let hook_active: bool;
724	    let mask: u32;
725	    let count: i32;
726	
727	    // C: if (lua_isnoneornil(L, arg+1)) { lua_settop(L, arg+1); func=NULL; mask=0; count=0; }
728	    if matches!(state.type_at(arg + 1), LuaType::None | LuaType::Nil) {
729	        lua_vm::api::set_top(state, arg + 1)?;
730	        hook_active = false;
731	        mask = 0;
732	        count = 0;
733	    } else {
734	        // C: const char *smask = luaL_checkstring(L, arg+2);
735	        let smask: Vec<u8> = state.check_arg_string(arg + 2)?.to_vec();
736	        // C: luaL_checktype(L, arg+1, LUA_TFUNCTION);
737	        state.check_arg_type(arg + 1, LuaType::Function)?;
738	        // C: count = (int)luaL_optinteger(L, arg + 3, 0);
739	        count = state.opt_arg_integer(arg + 3, 0)? as i32;
740	        // C: func = hookf; mask = makemask(smask, count);
741	        hook_active = true;
742	        mask = make_mask(&smask, count);
743	    }
744	
745	    // C: if (!luaL_getsubtable(L, LUA_REGISTRYINDEX, HOOKKEY)) { /* newly created */ }
746	    if !state.get_or_create_registry_subtable(HOOKKEY)? {
747	        // Table was just created. Set it up as a weak-keyed table so that
748	        // thread keys do not prevent GC of finished threads.
749	        // C: lua_pushliteral(L, "k"); lua_setfield(L, -2, "__mode");
750	        let k = state.intern_str(b"k")?;
751	        state.push(LuaValue::Str(k));
752	        state.set_field(-2, b"__mode")?;
753	        // C: lua_pushvalue(L, -1); lua_setmetatable(L, -2);
754	        state.push_value_at(-1)?;
755	        state.set_metatable(-2)?;
756	    }
757	
758	    check_cross_thread_stack(state, target_is_self, 1)?;
759	
760	    // C: lua_pushthread(L1); lua_xmove(L1, L, 1);  /* key = target thread */
761	    if target_is_self {
762	        state.push_thread()?;
763	    } else {
764	        // TODO(port): push L1 as a thread value and move it to the current stack
765	        // for use as the hook-table key. Requires cross-thread borrow.
766	    }
767	    // C: lua_pushvalue(L, arg + 1);  /* value = hook function (or nil) */
768	    state.push_value_at(arg + 1)?;
769	    // C: lua_rawset(L, -3);  /* hooktable[L1] = hook */
770	    state.raw_set(-3)?;
771	
772	    // C: lua_sethook(L1, func, mask, count);
773	    if target_is_self {
774	        // TODO(phase-b): HookFn type in state_stub takes &mut LuaDebug; set_hook takes lua_CFunction. Wire through real hook registry once lua-vm lands.
775	        let _ = hook_active;
776	        state.set_hook_full(None, mask, count)?;
777	    } else {
778	        // TODO(port): set hook on another thread — requires &mut LuaState for
779	        // the target concurrently with the current state.
780	    }
781	
782	    Ok(0)
783	}
