785	/// `debug.gethook([thread])` — return the current hook function, mask string,
786	/// and count. Returns the fail value if no hook is installed.
787	///
788	/// C: `static int db_gethook(lua_State *L)`
789	pub(crate) fn get_hook(state: &mut LuaState) -> Result<usize, LuaError> {
790	    // C: int arg; lua_State *L1 = getthread(L, &arg);
791	    let (_arg, other_thread) = getthread(state);
792	    let target_is_self = other_thread.is_none();
793	
794	    // C: char buff[5]; int mask = lua_gethookmask(L1);
795	    let mask: u32 = if target_is_self {
796	        state.get_hook_mask()
797	    } else {
798	        // TODO(port): retrieve hook mask from another thread.
799	        0u32
800	    };
801	
802	    // C: lua_Hook hook = lua_gethook(L1);
803	    let hook_is_set: bool = if target_is_self {
804	        state.hook_is_set()
805	    } else {
806	        // TODO(port): retrieve hook presence from another thread.
807	        false
808	    };
809	
810	    // C: if (hook == NULL) { luaL_pushfail(L); return 1; }
811	    if !hook_is_set {
812	        state.push_fail();
813	        return Ok(1);
814	    }
815	
816	    // C: else if (hook != hookf)  /* external hook? */
817	    //      lua_pushliteral(L, "external hook");
818	    let hook_is_internal: bool = if target_is_self {
819	        // TODO(port): comparing hook function identity requires the VM to expose
820	        // whether the currently-installed hook is the Lua-managed `hookf` or an
821	        // external callback. Needs a dedicated predicate on LuaState (Phase B).
822	        state.hook_is_internal_lua_hook()
823	    } else {
824	        // TODO(port): retrieve hook kind from another thread.
825	        false
826	    };
827	
828	    if !hook_is_internal {
829	        // C: lua_pushliteral(L, "external hook");
830	        let s = state.intern_str(b"external hook")?;
831	        state.push(LuaValue::Str(s));
832	    } else {
833	        // C: else { /* hook table must exist */
834	        // C:   lua_getfield(L, LUA_REGISTRYINDEX, HOOKKEY);
835	        state.get_registry_field(HOOKKEY)?;
836	        check_cross_thread_stack(state, target_is_self, 1)?;
837	        // C:   lua_pushthread(L1); lua_xmove(L1, L, 1);
838	        if target_is_self {
839	            state.push_thread();
840	        } else {
841	            // TODO(port): cross-thread thread-push for hook table lookup.
842	        }
843	        // C:   lua_rawget(L, -2);  /* 1st result = hooktable[L1] */
844	        state.raw_get(-2);
845	        // C:   lua_remove(L, -2);  /* remove hook table */
846	        state.remove(-2);
847	    }
848	
849	    // C: lua_pushstring(L, unmakemask(mask, buff));  /* 2nd result = mask string */
850	    let smask = unmake_mask(mask);
851	    let ls = state.intern_str(&smask)?;
852	    state.push(LuaValue::Str(ls));
853	
854	    // C: lua_pushinteger(L, lua_gethookcount(L1));  /* 3rd result = count */
855	    let hook_count: i32 = if target_is_self {
856	        state.get_hook_count()
857	    } else {
858	        // TODO(port): retrieve hook count from another thread.
859	        0i32
860	    };
861	    state.push(LuaValue::Int(hook_count as i64));
862	
863	    Ok(3)
864	}
