866	/// `debug.debug()` — enter an interactive debug REPL.
867	///
868	/// Reads Lua source lines from stdin, compiles and runs each one. On EOF or
869	/// when the user types `cont`, returns control to the caller. Errors in
870	/// commands are printed to stderr and the loop continues.
871	///
872	/// C: `static int db_debug(lua_State *L)`
873	pub(crate) fn debug_interactive(state: &mut LuaState) -> Result<usize, LuaError> {
874	    let stdin = io::stdin();
875	    loop {
876	        // C: lua_writestringerror("%s", "lua_debug> ");
877	        eprint!("lua_debug> ");
878	        let _ = io::stderr().flush();
879	
880	        // C: if (fgets(buffer, sizeof(buffer), stdin) == NULL || strcmp(buffer, "cont\n") == 0)
881	        //        return 0;
882	        // PORT NOTE: using String for the line buffer is Rust I/O infrastructure,
883	        // not Lua data. The bytes are immediately converted to &[u8] before being
884	        // passed into the Lua API.
885	        let mut line = String::new();
886	        let n = stdin
887	            .lock()
888	            .read_line(&mut line)
889	            .map_err(|e| LuaError::runtime(format_args!("stdin read error: {}", e)))?;
890	
891	        if n == 0 || line == "cont\n" {
892	            return Ok(0);
893	        }
894	
895	        let bytes: &[u8] = line.as_bytes();
896	
897	        // C: if (luaL_loadbuffer(L, buffer, strlen(buffer), "=(debug command)") ||
898	        //        lua_pcall(L, 0, 0, 0))
899	        //      lua_writestringerror("%s\n", luaL_tolstring(L, -1, NULL));
900	        let result = state
901	            .load_buffer(bytes, b"=(debug command)", None)
902	            .and_then(|_| state.protected_call(0, 0, 0));
903	
904	        if let Err(_) = result {
905	            // TODO(port): display the error via state.coerce_to_string(-1) which
906	            // maps to luaL_tolstring. The exact method name for the coercing
907	            // to-string operation and the stderr-write helper need to be established
908	            // in Phase B (lua-vm/src/api.rs).
909	            eprintln!("(error in debug command)");
910	            state.pop_n(1);
911	        }
912	
913	        // C: lua_settop(L, 0);  /* remove eventual returns */
914	        lua_vm::api::set_top(state, 0)?;
915	    }
916	}
