918	/// `debug.traceback([thread,] [message [, level]])` — return a traceback string.
919	///
920	/// If `message` is present but is not a string, it is returned unchanged.
921	/// Otherwise a stack traceback is generated and optionally prepended with
922	/// `message`.
923	///
924	/// C: `static int db_traceback(lua_State *L)`
925	pub(crate) fn traceback(state: &mut LuaState) -> Result<usize, LuaError> {
926	    // C: int arg; lua_State *L1 = getthread(L, &arg);
927	    let (arg, other_thread) = getthread(state);
928	    let target_is_self = other_thread.is_none();
929	
930	    // C: const char *msg = lua_tostring(L, arg + 1);
931	    // Immediately clone to Vec<u8> to free the borrow on `state`.
932	    let msg_owned: Option<Vec<u8>> = state
933	        .to_lua_string(arg + 1)
934	        .map(|s: GcRef<LuaString>| s.as_bytes().to_vec());
935	
936	    // C: if (msg == NULL && !lua_isnoneornil(L, arg + 1))
937	    let arg1_ty = state.type_at(arg + 1);
938	    if msg_owned.is_none() && !matches!(arg1_ty, LuaType::None | LuaType::Nil) {
939	        // C: lua_pushvalue(L, arg + 1);  /* return it untouched */
940	        state.push_value_at(arg + 1)?;
941	    } else {
942	        // C: int level = (int)luaL_optinteger(L, arg+2, (L == L1) ? 1 : 0);
943	        let default_level: i64 = if target_is_self { 1 } else { 0 };
944	        let level = state.opt_arg_integer(arg + 2, default_level)? as i32;
945	
946	        // C: luaL_traceback(L, L1, msg, level);
947	        // TODO(phase-b): cross-thread traceback (other_thread != None) still
948	        // requires simultaneous &mut access to two LuaState; the
949	        // self-traceback path is wired up here.
950	        if other_thread.is_some() {
951	            let _ = other_thread;
952	            let _ = (msg_owned, level);
953	            state.push(LuaValue::Nil);
954	        } else {
955	            crate::auxlib::traceback(state, None, msg_owned.as_deref(), level)?;
956	        }
957	    }
958	    Ok(1)
959	}
