pub fn set_hook(
    state: &mut LuaState,
    func: Option<Box<dyn FnMut(&mut LuaState, &LuaDebug)>>,
    mask: i32,
    count: i32,
) {
    // C: if (func == NULL || mask == 0) { mask = 0; func = NULL; }
    let (func, mask) = if func.is_none() || mask == 0 {
        (None, 0i32)
    } else {
        (func, mask)
    };
    // C: L->hook = func; L->basehookcount = count;
    state.set_hook(func);
