        debug_assert!(
            state.get_debug_info(b"lS", ar).is_ok(),
            "lua_getinfo(\"lS\") should always succeed in hookf"
        );

        // C: lua_call(L, 2, 0);
        state.call(2, 0)?;
    }
    Ok(())
}

